-- ============================================
-- Section 7: Recreate employee_fraud_metrics materialized view
-- ============================================

DROP MATERIALIZED VIEW IF EXISTS employee_fraud_metrics;

CREATE MATERIALIZED VIEW employee_fraud_metrics AS
SELECT u.id AS user_id,
    u.tenant_id,
    (((u.first_name)::text || ' '::text) || (u.last_name)::text) AS employee_name,
    u.role,
    count(DISTINCT t.transaction_id) AS total_transactions,
    count(DISTINCT t.transaction_id) FILTER (WHERE ((t.status)::text = 'voided'::text)) AS void_count,
    count(DISTINCT r.id) AS refund_count,
    COALESCE(sum(t.discount_amount), (0)::numeric) AS total_discounts_given,
    COALESCE(avg(t.discount_amount) FILTER (WHERE (t.discount_amount > (0)::numeric)), (0)::numeric) AS avg_discount,
    count(*) FILTER (WHERE (t.discount_amount > (0)::numeric)) AS discount_transaction_count,
    COALESCE(sum(r.total_refund_amount), (0)::numeric) AS total_refund_amount,
    count(DISTINCT fa.id) AS fraud_alert_count,
    max(t.created_at) AS last_transaction_at
   FROM (((users u
     LEFT JOIN transactions t ON (((t.user_id = u.id) AND (t.created_at > (now() - '90 days'::interval)))))
     LEFT JOIN pos_returns r ON (((r.processed_by = u.id) AND (r.created_at > (now() - '90 days'::interval)))))
     LEFT JOIN fraud_alerts fa ON (((fa.user_id = u.id) AND (fa.created_at > (now() - '90 days'::interval)))))
  WHERE (u.is_active = true)
  GROUP BY u.id, u.tenant_id, u.first_name, u.last_name, u.role;

CREATE INDEX IF NOT EXISTS idx_employee_fraud_metrics_tenant_id ON employee_fraud_metrics(tenant_id);

COMMIT;
